/**
 * Writes public/legacy-jks-bundle.css with @import in cascade-safe order
 * (plugins + theme base → layout parts → page overrides → form module styles).
 */
import fs from 'node:fs'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const JKS_VUE = path.resolve(__dirname, '..')
const PUBLIC = path.join(JKS_VUE, 'public')
const CSS_ROOT = path.join(PUBLIC, 'css')
const OUT = path.join(PUBLIC, 'legacy-jks-bundle.css')

function walkCss(dir) {
  const out = []
  if (!fs.existsSync(dir)) return out
  for (const ent of fs.readdirSync(dir, { withFileTypes: true })) {
    const p = path.join(dir, ent.name)
    if (ent.isDirectory()) out.push(...walkCss(p))
    else if (ent.name.endsWith('.css')) out.push(p)
  }
  return out
}

function relToPublic(abs) {
  return path.relative(PUBLIC, abs).split(path.sep).join('/')
}

const allFiles = walkCss(CSS_ROOT)
const relSet = new Set(allFiles.map(relToPublic))

/** Explicit order; later entries override earlier ones. */
const PRIORITY = [
  'css/wp-content__plugins__bravis-addons__assets__css__main.css',
  'css/wp-content__plugins__bravis-addons__assets__libs__font-awesome-pro__css__all.min.css',
  'css/wp-content__plugins__contact-form-7__includes__css__styles.css',
  'css/wp-content__plugins__elementor__assets__lib__eicons__css__elementor-icons.min.css',
  'css/wp-content__uploads__elementor__css__custom-frontend.min.css',
  'css/wp-content__plugins__elementor__assets__css__widget-heading.min.css',
  'css/wp-content__plugins__elementor__assets__lib__animations__styles__fadeInUp.min.css',
  'css/wp-content__themes__immigway__assets__css__libs__magnific-popup.css',
  'css/wp-content__themes__immigway__assets__css__libs__animate.min.css',
  'css/wp-content__themes__immigway__assets__fonts__flaticon__css__flaticon.css',
  'css/wp-content__themes__immigway__assets__css__caseicon.css',
  'css/wp-content__themes__immigway__assets__css__grid.css',
  'css/wp-content__themes__immigway__assets__css__style.css',
  'css/wp-content__themes__immigway__style.css',
  'css/wp-includes__css__dist__block-library__style.min.css',
  'css/wp-content__uploads__elementor__google-fonts__css__roboto.css',
  'css/wp-content__uploads__elementor__google-fonts__css__robotoslab.css',
  'css/wp-content__uploads__elementor__google-fonts__css__rubik.css',
  'css/wp-content__uploads__elementor__google-fonts__css__ptserif.css',
  'css/wp-content__uploads__elementor__google-fonts__css__sourcesanspro.css',
  'css/wp-content__uploads__elementor__google-fonts__css__poppins.css',
  'css/wp-content__uploads__elementor__css__custom-widget-icon-list.min.css',
  'css/wp-content__themes__immigway__assets__css__libs__datetimepicker.css',
]

const ordered = []
for (const r of PRIORITY) {
  if (relSet.has(r)) {
    ordered.push(r)
    relSet.delete(r)
  }
}

const pageCss = [...relSet].filter((r) => r.startsWith('css/pages/')).sort((a, b) => a.localeCompare(b))
for (const r of pageCss) {
  ordered.push(r)
  relSet.delete(r)
}

const forminatorRest = [...relSet].sort((a, b) => a.localeCompare(b))
ordered.push(...forminatorRest)

if (ordered.length !== allFiles.length) {
  const miss = allFiles.map(relToPublic).filter((r) => !ordered.includes(r))
  throw new Error(`CSS count mismatch: disk ${allFiles.length}, ordered ${ordered.length}, missing: ${miss.join(', ')}`)
}

const lines = [
  '/* Auto-generated by scripts/build-legacy-css-bundle.mjs */',
  '',
  ...ordered.map((r) => `@import url('/${r}');`),
  '',
]
fs.writeFileSync(OUT, lines.join('\n'), 'utf8')
console.log('wrote', OUT, `(${ordered.length} imports)`)
